import os
import numpy as np

working_dir = os.path.join(os.getcwd(), "working")
file_path = os.path.join(working_dir, "experiment_data.npy")

experiment_data = np.load(file_path, allow_pickle=True).item()


def safe_last_scalar(metric_list):
    if not metric_list:
        return None
    _, value = metric_list[-1]
    return value


def safe_best_min(metric_list):
    if not metric_list:
        return None
    return min(value for _, value in metric_list)


def safe_best_max(metric_list):
    if not metric_list:
        return None
    return max(value for _, value in metric_list)


def format_value(value):
    if value is None:
        return "N/A"
    if isinstance(value, (float, np.floating)):
        return f"{float(value):.6f}"
    return str(value)


for dataset_name, dataset_data in experiment_data.items():
    print(f"Dataset: {dataset_name}")

    metrics = dataset_data.get("metrics", {})
    losses = dataset_data.get("losses", {})
    stream_results = dataset_data.get("stream_results", {})

    train_accuracy_final = safe_last_scalar(metrics.get("train", []))
    validation_accuracy_final = safe_last_scalar(metrics.get("val", []))
    training_loss_final = safe_last_scalar(losses.get("train", []))
    validation_loss_final = safe_last_scalar(losses.get("val", []))
    validation_loss_best = safe_best_min(losses.get("val", []))
    validation_accuracy_best = safe_best_max(metrics.get("val", []))

    if train_accuracy_final is not None:
        print(f"  Train accuracy (final): {format_value(train_accuracy_final)}")
    if validation_accuracy_final is not None:
        print(
            f"  Validation accuracy (final): {format_value(validation_accuracy_final)}"
        )
    if validation_accuracy_best is not None:
        print(f"  Validation accuracy (best): {format_value(validation_accuracy_best)}")
    if training_loss_final is not None:
        print(f"  Training loss (final): {format_value(training_loss_final)}")
    if validation_loss_final is not None:
        print(f"  Validation loss (final): {format_value(validation_loss_final)}")
    if validation_loss_best is not None:
        print(f"  Validation loss (best): {format_value(validation_loss_best)}")

    test_metrics = metrics.get("test", [])
    if test_metrics:
        _, test_value = test_metrics[-1]
        if isinstance(test_value, dict):
            if "frozen_acc" in test_value:
                print(
                    f"  Test shifted-stream accuracy (frozen adaptation): {format_value(test_value['frozen_acc'])}"
                )
            if "always_acc" in test_value:
                print(
                    f"  Test shifted-stream accuracy (always adaptation): {format_value(test_value['always_acc'])}"
                )
            if "gated_acc" in test_value:
                print(
                    f"  Test shifted-stream accuracy (gated adaptation): {format_value(test_value['gated_acc'])}"
                )
        else:
            print(f"  Test metric (final): {format_value(test_value)}")

    for mode_name, result_dict in stream_results.items():
        accuracy_key = "Shifted-Stream Accuracy"
        if accuracy_key in result_dict:
            print(
                f"  Shifted-stream accuracy ({mode_name}): {format_value(result_dict[accuracy_key])}"
            )
        if "trigger_rate" in result_dict:
            print(
                f"  Adaptation trigger rate ({mode_name}): {format_value(result_dict['trigger_rate'])}"
            )

    print()

